import os
import signal
import time
from pathlib import Path

patterns = [
    "proofbench_smoke_9d6276f",
    "hnode096:29541",
    "--port=29541",
    "session_2026-06-13_19-49-06",
]
own_pid = os.getpid()
own_ppid = os.getppid()
own_pgid = os.getpgrp()


def read_process_text(pid):
    proc = Path('/proc') / str(pid)
    try:
        cmd = (proc / 'cmdline').read_bytes().replace(b'\0', b' ').decode('utf-8', 'replace')
    except Exception:
        cmd = ''
    try:
        env = (proc / 'environ').read_bytes().replace(b'\0', b' ').decode('utf-8', 'replace')
    except Exception:
        env = ''
    return cmd, env


def scan():
    groups = {}
    for proc in Path('/proc').iterdir():
        if not proc.name.isdigit():
            continue
        pid = int(proc.name)
        if pid in {own_pid, own_ppid}:
            continue
        try:
            pgid = os.getpgid(pid)
        except Exception:
            continue
        if pgid == own_pgid:
            continue
        cmd, env = read_process_text(pid)
        blob = cmd + ' ' + env
        if 'train_operator.py' in cmd and '--operator_mode' in cmd:
            continue
        if any(pattern in blob for pattern in patterns):
            groups.setdefault(pgid, []).append((pid, cmd[:300]))
    return groups


print('HOST=' + os.uname().nodename)
groups = scan()
print('groups_before=' + str(len(groups)))
for pgid, procs in sorted(groups.items()):
    print('TARGET_PGID', pgid, 'PIDS', [pid for pid, _ in procs], 'CMD', procs[0][1])
    try:
        os.killpg(pgid, signal.SIGTERM)
        print('sent_SIGTERM', pgid)
    except ProcessLookupError:
        pass
    except Exception as exc:
        print('sigterm_failed', pgid, type(exc).__name__, exc)

time.sleep(5)
groups = scan()
print('groups_after_sigterm=' + str(len(groups)))
for pgid, procs in sorted(groups.items()):
    try:
        os.killpg(pgid, signal.SIGKILL)
        print('sent_SIGKILL', pgid)
    except ProcessLookupError:
        pass
    except Exception as exc:
        print('sigkill_failed', pgid, type(exc).__name__, exc)

time.sleep(1)
print('groups_final=' + str(len(scan())))
